import React, {useState} from 'react';
import {Fab, Grid} from '@material-ui/core';
import {makeStyles} from "@material-ui/core/styles";
import TableTransactions from "./table";
import DateToday from "../helpingFunctions/date_today";
import ButtonGroup from "@material-ui/core/ButtonGroup";
import Button from "@material-ui/core/Button";




function Transections(props) {
    const [add_transaction, setAdd_transaction] = useState(false)
    const [DOW, setDOW] = useState([]);

    const [id, setId] = useState(false)
    const [Account, setAccount] = useState([]);
    const [reviewed, setReviewed] = useState(false);
    const [Description, setDescription] = useState("");
    const [pDate, setDate] = useState(DateToday());
    const [Notes, setNotes] = useState("");
    const [totalAmount, setTotalAmount] = useState(0);
    const [vendor, setVendor] = useState("")
    const [split, setSplit] = useState(
        [
            {id: 1, category: "", customer: "", amount: 0}
        ]
    );


    function IncomeClick() {
        setDOW(1)
        Clear();
        setAdd_transaction(true)
    }

    function ExpenseClick() {
        setDOW(2)
        Clear();
        setAdd_transaction(true)
    }

    function JournalClick() {
        setDOW(3)
        Clear();
        setSplit([
            {id: 1, category: "", description: "", amount: 0, type: 1},
            {id: 2, category: "", description: "", amount: 0, type: 2},
        ])
        setAdd_transaction(true)
    }

    function Clear() {
        setId(false)
        setReviewed(false)
        setDescription("")
        setDate(DateToday())
        setNotes("")
        setTotalAmount(0)
        setVendor("")
        setSplit(
            [{id: 1, category: "", customer: "", amount: 0}]
        )
        setAccount([])
    }

    return (
        <div>
            <Grid container>
                <Grid item lg={5} md={5} sm={5} xs={12} xl={5}>
                    <h1>Transactions</h1>
                    {!props.current_date?null: <div style={{padding:10}}>
                        <h3>between {props.prev_date===null? new Date(new Date(props.current_date).setDate(1)).toDateString(): new Date(props.prev_date).toDateString() } and {new Date(props.current_date).toDateString()}</h3>
                    </div>}
                </Grid>
                <Grid style={{marginTop: 15, marginBottom: 15}} item lg={4} md={5} sm={5} xs={12}
                      xl={3}>

                        {props.id?
                            <Button style={{borderRadius:30 }}   color="as" variant={"contained"} onClick={IncomeClick}>Add Transaction</Button>
                            : <ButtonGroup style={{borderRadius:30 }}  color="as" variant={"contained"} aria-label="outlined primary button group">

                                <Button style={{borderTopLeftRadius:30, borderBottomLeftRadius:30}}  onClick={IncomeClick}>Add Income</Button>
                                <Button onClick={ExpenseClick}>Add Expense</Button>
                                <Button style={{borderTopRightRadius:30, borderBottomRightRadius:30 }}  onClick={JournalClick}>Add Journal</Button>
                             </ButtonGroup>
                        }



                </Grid>

            </Grid>
            <TableTransactions


                id={id}
                Account={Account}
                reviewed={reviewed}
                Description={Description}
                Date={pDate}
                Notes={Notes}
                totalAmount={totalAmount}
                vendor={vendor}
                split={split}
                DOW={DOW}
                add_transaction={add_transaction}

                setId={setId}
                setReviewed={setReviewed}
                setDescription={setDescription}
                setDate={setDate}
                setNotes={setNotes}
                setTotalAmount={setTotalAmount}
                setVendor={setVendor}
                setSplit={setSplit}
                setAccount={setAccount}

                setDOW={setDOW}
                setAdd_transaction={setAdd_transaction}

                Clear={Clear}

                filter={props.id}
                current_date={props.current_date}
                prev_date={props.prev_date}
            />
        </div>
    )
        ;
}

export default Transections;