import React, {Fragment, useEffect, useState} from "react";
import Paper from "@material-ui/core/Paper";
import baseURL from "../helpingFunctions/baseUrl";
import {Button, Divider, Fab, MenuItem, TextField} from "@material-ui/core";
import ListSubheader from "@material-ui/core/ListSubheader";
import {DeleteForever, Done, FileCopy, Info} from "@material-ui/icons";
import {makeStyles} from "@material-ui/core/styles";
import axios from 'axios'
import DateToday from "../helpingFunctions/date_today";

const useStyles = makeStyles(theme => ({
    Divider: {
        marginTop: 20,
        marginBottom: 20
    },
    Container: {
        height: 551,

        overflowY: "scroll"
    },
    TextField: {
        marginTop: 15,
        width: 414
    },
    TextFieldDuelFirst: {
        width: 220
    },
    TextFieldDuelSecond: {
        width: 195
    },
    SubMenu: {
        marginLeft: 20,
    },
    SubButtons: {
        marginLeft: 6,
        boxShadow: "none"
    },
    SubSuccess: {
        marginLeft: 6,
        color: "green !important",
        border: "1px solid green",
        boxShadow: "none"
    },
}));

const transactions = [
    {
        value: '1',
        label: 'Deposit',
    },
    {
        value: '2',
        label: 'Withdrawal',
    },
];

function AddTransaction(props) {
    useEffect(() => {
        getAccounts()
        getSplitAccounts()
        getCustomers()
        getVendors()
    }, [1])

    const {
        Account,
        DOW,
        Description,
        Date,
        Notes,
        totalAmount,
        vendor,
        split,
        id,
        setSave,
        save,
        setAccount,
        setDOW,
        setDescription,
        setDate,
        setId,
        setNotes,
        setTotalAmount,
        setVendor,
        setSplit,
        reviewed,
        setReviewed
    } = props


    const classes = useStyles();


    const [Accounts, setAccounts] = useState([]);
    const [Customers, setCustomers] = useState([]);
    const [splitAccounts, setSplitAccounts] = useState([]);
    const [vendor_accounts, setVendorAccounts] = useState([]);
    const [ven_add_remove, setVenAddRemove] = useState(false);


    console.log(props.Description)

    function getVendors() {
        axios.get(baseURL + "crm/api/vendors-list/").then((r) => {
            setVendorAccounts(r.data)
        })
    }

    function getAccounts() {
        let result;
        axios.get(baseURL + "crm/api/deposit-accounts/", {
            params: {
                user: localStorage.getItem("user")
            }
        }).then((r) => {
            result = r.data
            setAccounts(result)
        })
    }


    function getSplitAccounts() {
        let result;
        axios.get(baseURL + "crm/api/split-accounts/", {
            params: {
                user: localStorage.getItem("user")
            }
        }).then((r) => {
            result = r.data
            setSplitAccounts(result)
        })
    }

    function getCustomers() {
        let result;
        axios.get(baseURL + "crm/api/customer-list/", {
            params: {
                user: localStorage.getItem("user")
            }
        }).then((r) => {
            result = r.data
            setCustomers(result)
        })
    }

    function Display(dup) {
        if (split.map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)
            !== parseInt(totalAmount) && split.length > 1) {

        } else {
            let t = [...split]
            if (t.length === 1)
                split[0].amount = totalAmount

            if (DOW == 1) {
                t.forEach((item) => {
                    item['type'] = 2
                })
                t.push({category: Account, amount: totalAmount, type: 1, vendor: vendor})
            }
            if (DOW == 2) {
                t.forEach((item) => {
                    item['type'] = 1
                })
                t.push({category: Account, amount: totalAmount, type: 2, vendor: vendor})
            }
            const test = {
                "user": localStorage.getItem("user"),
                "credit_debit": t,
                "description": Description,
                "date": Date,
                "type": DOW,
                "notes": Notes,
                "reviewed": reviewed,
            }

            if (!id || dup === "D")
                axios.post(baseURL + "crm/api/transections-list-create/", test).then((r) => {
                        console.log(r.data)
                        props.setSave(!props.save)
                    }
                )
            else if (id && dup === "del") {
                axios.delete(baseURL + "crm/api/transections-rud/" + id).then(() => {
                    props.setSave(!props.save)
                })
            } else {
                axios.put(baseURL + "crm/api/transections-rud/" + id, test).then((r) => {
                        console.log(r.data)
                        props.setSave(!props.save)
                    }
                )
            }

            console.log(test);
        }

    }

    function AddVendor() {
        setVenAddRemove(!ven_add_remove)
        setVendor(false)
    }


    return (
        <div style={{minWidth: 460}}>
            <Paper style={{padding: 10, borderBottom: "1px solid #e0e0e0", borderRadius: 0, height: "fit-content"}}
                   elevation={0}>
                <div>
                    Edit transaction details
                </div>
                <Divider className={classes.Divider}/>

                <div className={classes.Container}>
                    <TextField className={classes.TextField}
                               id="outlined-password-input"
                               label="Description"
                               type="text"
                               value={Description}
                               autoComplete="current-password"
                               variant="outlined"
                               onChange={(e) => {
                                   setDescription(e.target.value)
                               }}
                    />

                    <div style={{marginTop: 15}}>
                        <TextField className={classes.TextFieldDuelFirst}
                                   id="standard-select-currency"
                                   label="Account"
                                   select
                                   value={props.filter && Account.length===0?props.filter:Account}
                                   disabled={props.filter && Account.length===0}
                                   variant="outlined"
                                   onChange={(e) => {
                                       setAccount(e.target.value);
                                   }}
                        >
                            {Accounts.map((item) => {
                                return [
                                    <ListSubheader>{item.name}</ListSubheader>,
                                    item.accounting_child.map((it) => {
                                        return <MenuItem className={classes.SubMenu}
                                                         value={it.id}>{it.name}</MenuItem>
                                    })
                                ]
                            })}
                        </TextField>

                        <TextField
                            className={classes.TextFieldDuelSecond}
                            id="outlined-password-input"
                            label="Date"
                            type="date"
                            InputProps={Date && !props.current_date?null:{inputProps: {max:props.current_date, min :props.prev_date}}}
                            value={Date}
                            variant="outlined"
                            onChange={(e) => {
                                setDate(e.target.value)
                            }}
                        />
                    </div>

                    <div style={{marginTop: 15, width:450}}>
                        <TextField className={classes.TextFieldDuelFirst}
                                   id="standard-select-currency"
                                   label="Deposite or withdrawal"
                                   select
                                   variant="outlined"
                                   value={DOW}
                                   onChange={(e) => {
                                       setDOW(e.target.value)
                                   }}
                        >
                            {transactions.map(option => (
                                <MenuItem id={option.value} value={option.value}>
                                    {option.label}
                                </MenuItem>
                            ))}
                        </TextField>
                        <TextField className={classes.TextFieldDuelSecond}
                                   id="outlined-password-input"
                                   label="Total Amount"
                                   type="number"
                                   value={totalAmount}
                                   variant="outlined"
                                   onChange={(e) => {
                                       setTotalAmount(e.target.value)
                                   }}
                        />
                        {
                            ven_add_remove || vendor?
                                <TextField className={classes.TextField}
                                           label="Vendors"
                                           select
                                           variant="outlined"
                                           value={vendor}
                                           onChange={(e) => {
                                               setVendor(e.target.value)
                                           }}
                                >
                                    {vendor_accounts.map(option => (
                                        <MenuItem id={option.id} value={option.id}>
                                            {option.name}
                                        </MenuItem>
                                    ))}
                                </TextField> : null
                        }
                        <br/>
                        <Button style={{color: "Blue"}}
                                onClick={AddVendor}>{ven_add_remove || vendor? "Remove Vendor" : "Add vendor"}</Button>

                    </div>
                    <Divider className={classes.Divider}/>
                    <div style={{maxWidth: 415}}>
                        {
                            split.map((k, i) => {
                                let id = k.id;
                                let index = i;
                                if (split.find((item) => item.id === id).customer) {
                                    split.find((item) => item.id === id).cus = true
                                }
                                return <Fragment>
                                    <TextField
                                        className={classes.TextField}
                                        id="standard-select-currency"
                                        label="Category"
                                        select
                                        variant="outlined"
                                        value={split.find((item) => item.id === id).category}
                                        onChange={(e) => {
                                            let temp = split;
                                            temp.find((item) => item.id === id).category = e.target.value;
                                            setSplit([...temp])
                                        }}
                                    >
                                        {splitAccounts.map((item) => {
                                            return [
                                                <ListSubheader>{item.name}</ListSubheader>,
                                                item.accounting_child.map((it) => {
                                                    return <MenuItem className={classes.SubMenu}
                                                                     value={it.id}>{it.name}</MenuItem>
                                                })
                                            ]
                                        })}
                                    </TextField>

                                    {

                                        split.find((item) => item.id === id).cus ?

                                            <TextField className={classes.TextField}
                                                       id="standard-select-currency"
                                                       label="Customer"
                                                       select
                                                       variant="outlined"
                                                       value={split.find((item) => item.id === id).customer}
                                                       onChange={(e) => {
                                                           let temp = split;
                                                           temp.find((item) => item.id === id).customer = e.target.value;
                                                           setSplit([...temp])
                                                       }}
                                            >
                                                {Customers.map((item) => {
                                                    return <MenuItem className={classes.SubMenu}
                                                                     value={item.id}>{item.name}</MenuItem>

                                                })}
                                            </TextField>
                                            : null
                                    }
                                    <div style={{marginTop: 10}}>
                                        {split.length === 1 ? null :
                                            <TextField className={classes.TextFieldDuelSecond}
                                                       label="Amount"
                                                       variant="outlined"
                                                       id={index}
                                                       value={split.find((item) => item.id === id).amount}
                                                       onChange={(e) => {
                                                           let temp = split;
                                                           temp.find((item) => item.id === id).amount = e.target.value;
                                                           setSplit([...temp])
                                                       }}
                                            />
                                        }

                                        {index === 0 ? null : <Button onClick={() => {
                                            let temp = split;
                                            split.splice(index, 1)
                                            setSplit([...temp])
                                        }} size="small" style={{boxShadow: "none"}}>
                                            <DeleteForever/>
                                        </Button>}
                                    </div>
                                    <Button style={{color: "Blue"}}
                                            onClick={() => {
                                                let temp = split;
                                                temp.find((item) => item.id === id).cus =
                                                    !temp.find((item) => item.id === id).cus;
                                                temp.find((item) => item.id === id).customer = "";

                                                setSplit([...temp])
                                            }}

                                    >
                                        {!split.find((item) => item.id === id).cus ? "Add customer" : "Remove Customer"}
                                    </Button>

                                </Fragment>
                                // return <Split id={k.id} index={i}/>
                            })
                        }
                    </div>

                    <Divider style={{marginTop: 20, marginBottom: "-17px"}}/>

                    <div style={{textAlign: "center"}}>
                        <Button variant="outlined" size="small" color="primary"
                                style={{backgroundColor: "white"}} onClick={() => {
                            setSplit([...split, {
                                id: split[split.length - 1].id + 1,
                                category: "",
                                customer: "",
                                amount: 0,
                                cus: false
                            }])
                        }}>
                            Split this deposit <Info style={{marginLeft: 3}}/>
                        </Button>
                    </div>
                    <TextField className={classes.TextField}
                               id="outlined-password-input"
                               label="Notes"
                               type="text"
                               multiline
                               value={Notes}
                               autoComplete="current-password"
                               variant="outlined"
                               onChange={(e) => {
                                   setNotes(e.target.value)
                               }}
                    />
                    <div style={{marginTop: 10}}>Transaction last modified on <DateToday/>
                    </div>
                </div>
                <Divider style={{marginTop: 13, marginBottom: 5}}/>

                <div style={{textAlign: "center"}}>
                    {
                        split.map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)
                        !== parseInt(totalAmount) && split.length > 1 ?
                            <div style={{color: "red"}}>Split sum is not equal to total amount </div> : null
                    }
                    <Fab size="small" style={{boxShadow: "none"}} onClick={() => {
                        Display("del")
                    }}>
                        <DeleteForever/>
                    </Fab>
                    <Fab size="small" className={classes.SubButtons} onClick={() => {
                        Display("D")
                    }}>
                        <FileCopy/>
                    </Fab>
                    <Fab disabled={!split[split.length - 1].category} variant="extended" size="small"
                         className={reviewed ? classes.SubSuccess : classes.SubButtons}
                         onClick={() => setReviewed(!reviewed)}>

                        <Done/> Mark as reviewed
                    </Fab>
                    <Fab variant="extended" color={"primary"} size="small"
                         className={classes.SubButtons} onClick={() => {
                        Display();
                    }}>

                        Save
                    </Fab>
                </div>
            </Paper>
        </div>
    )

}

export default AddTransaction;