import React, {useEffect, useState} from "react";
import Paper from "@material-ui/core/Paper";
import Grid from "@material-ui/core/Grid";
import Divider from "@material-ui/core/Divider";
import Typography from "@material-ui/core/Typography";
import axios from "axios";
import baseURL from "../helpingFunctions/baseUrl";
import Button from "@material-ui/core/Button";
import Dialog from "@material-ui/core/Dialog";
import DialogTitle from "@material-ui/core/DialogTitle";
import TextField from "@material-ui/core/TextField";
import {ArrowDropDown, ArrowDropUp, Cancel, CheckCircle, Close, Edit} from "@material-ui/icons"
import DateToday from "../helpingFunctions/date_today";
import Tooltip from "@material-ui/core/Tooltip";
import {A} from "hookrouter";
import ReconcileTransactions from "./transections";

function Recompilation() {

    const [accounts, setAccounts] = useState([]);
    const [refresh, setRefresh] = useState(false);
    const [dialog, setDialog] = useState(false);
    const [selectedAccount, setSelectedAccount] = useState({});
    const [amount, setAmount] = useState();
    const [date, setDate] = useState(DateToday);
    const [open_reconciliation, setOpenReconciliation] = useState(false);
    const [show_hover, setShowHover] = useState([]);
    const [reconcile_info, setReconcileInfo] = useState([]);
    const [dropdown, setDropdown] = useState({});


    function handleReconciliationOpenCLose() {
        setOpenReconciliation(!open_reconciliation)
    }

    useEffect(() => {
        axios.get(baseURL + "crm/api/reconciliation-accounts/", {
            params: {
                user: localStorage.getItem("user")
            }
        }).then((result) => {
            setAccounts(result.data)
        })
    }, [refresh])

    function openDialog(name, id, reconciliation_id, amount, t_amount, date) {
        if (dialog) {
            setDate(DateToday)
            setAmount("")
            setSelectedAccount({})
        } else {
            setDate(date)
            setAmount(amount)
            setSelectedAccount({name, id, reconciliation_id, amount, t_amount})
        }
        setDialog(!dialog)
    }

    async function SubmitReconciliation() {
        let user = await localStorage.getItem("user");
        let url = selectedAccount.reconciliation_id ? baseURL + "crm/api/reconciliation-rud/" + selectedAccount.reconciliation_id : baseURL + "crm/api/reconciliation-create";
        if (selectedAccount.reconciliation_id) {
            axios.put(url, {
                "amount": amount,
                "date": date.toString(),
                "user": user,
                "account": selectedAccount.id
            }).then(() => setRefresh(!refresh))
            setDialog(!dialog)
        } else {
            axios.post(url, {
                "amount": amount,
                "date": date.toString(),
                "user": user,
                "account": selectedAccount.id
            }).then(() => setRefresh(!refresh))
            setDialog(!dialog)
        }

    }

    console.log(dropdown)

    function getIcon(t_amount, amountt, date, index, filter_from) {
        let date_p;
        if (index === 0) {
            date_p = false
        } else {

            date_p = JSON.parse(filter_from.reconciliation_list)[index - 1].date
        }


        let new_amount = (JSON.parse(filter_from.credit_debit).filter((item) => item.type == 2 && new Date(item.acctransactiondetail__date) > new Date(date_p) && new Date(item.acctransactiondetail__date) <= new Date(date))).reduce((prev, cur) => prev + cur.amount, 0) -
            (JSON.parse(filter_from.credit_debit).filter((item) => item.type == 1 && new Date(item.acctransactiondetail__date) > new Date(date_p) && new Date(item.acctransactiondetail__date) <= new Date(date))).reduce((prev, cur) => prev + cur.amount, 0)
        return [amountt, new_amount]
    }

    return <Grid container justify={"center"}>
        <Grid item xl={9} md={10} sm={11} xs={12}>
            <Paper style={{boxShadow: "none", border: "1px solid #e0e0e0"}}>
                <Typography style={{padding: 20}} variant={"h6"}> Manually Added Transactions</Typography>
                <Divider/>
                {accounts.map((item) => {
                    return <> <Grid container justify={"center"} style={{marginBottom: 20}}>
                        <Grid item xl lg sm xs>
                            <Typography style={{padding: 10, fontWeight: "bold"}} variant={"subtitle1"}>
                                {item.name}
                            </Typography>

                            {
                                (JSON.parse(item.reconciliation_list).map((item_s, index) => {
                                    let [total_amount, current_amount] = getIcon((JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                        (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0),
                                        item_s.amount, item_s.date, index, item
                                    )
                                    return [total_amount, current_amount]
                                })).filter((item) => {
                                    return item[0] !== item[1]
                                }).length === 0 ?
                                    <div style={{
                                        backgroundColor: "rgba(28,248,0,0.24)",
                                        color: "#185012",
                                        fontWeight: "bold",
                                        padding: 5,
                                        width: 300,
                                        borderTopRightRadius: "30px",
                                        borderBottomRightRadius: "30px"
                                    }}>
                                        <div style={{marginLeft: 10}}>
                                            Reconciled
                                        </div>
                                    </div>
                                    : (JSON.parse(item.reconciliation_list).map((item_s, index) => {
                                        let [total_amount, current_amount] = getIcon((JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                            (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0),
                                            item_s.amount, item_s.date, index, item
                                        )
                                        return [total_amount, current_amount]
                                    })).filter((item) => {
                                        return item[0] !== item[1]
                                    }).length === 1 ?
                                    <div style={{
                                        backgroundColor: "rgba(255,175,0,0.24)",
                                        color: "#bd690b",
                                        fontWeight: "bold",
                                        padding: 5,
                                        width: 300,
                                        borderTopRightRadius: "30px",
                                        borderBottomRightRadius: "30px"
                                    }}>
                                        <div style={{marginLeft: 10}}>
                                            Unreconciled
                                        </div>
                                    </div>
                                    : <div style={{
                                        backgroundColor: "rgba(255,0,0,0.24)",
                                        color: "#bd0b0b",
                                        fontWeight: "bold",
                                        padding: 5,
                                        width: 300,
                                        borderTopRightRadius: "30px",
                                        borderBottomRightRadius: "30px"
                                    }}>
                                        <div style={{marginLeft: 10}}>
                                            Needs Attention
                                        </div>
                                    </div>
                            }
                        </Grid>
                        <div style={{position: "relative", width: 600, margin: "auto", textAlign: "center"}}>
                            <Grid item xl lg sm xs>
                                {show_hover.id === item.id && dropdown[item.id]?
                                    <Paper elevation={7}
                                           style={{marginTop: 5, height: "fit-content", display: "flex", padding: 20}}>

                                        <Grid container spacing={3}>
                                            <Grid item xl lg sm md>
                                                <div>
                                                    Statement Balance
                                                </div>
                                                <div style={{fontSize: 35}}>
                                                    {show_hover.total_amount}<Edit
                                                    onClick={() => {
                                                        openDialog(show_hover.name, show_hover.id, show_hover.item_s, show_hover.amount,
                                                            show_hover.an_other_amount, show_hover.date)
                                                        setShowHover({})
                                                    }}
                                                    style={{cursor: "pointer", marginTop: 10, marginLeft: 10}}/>
                                                </div>

                                            </Grid>
                                            <Grid item xl lg sm md>
                                                <div>
                                                    Wave Balance
                                                </div>
                                                <div style={{fontSize: 35}}>
                                                    {show_hover.current_amount}
                                                </div>
                                            </Grid>
                                            <Grid item xl lg sm md>
                                                <div>
                                                    Difference
                                                </div>
                                                <div
                                                    style={show_hover.total_amount - show_hover.current_amount === 0 ? {
                                                        fontSize: 35,
                                                        color: "#78db72"
                                                    } : {fontSize: 35, color: "orange"}}>
                                                    {show_hover.total_amount - show_hover.current_amount}
                                                </div>
                                            </Grid>

                                        </Grid>
                                        <Close style={{float: "right"}} onClick={() => {
                                            setShowHover({});
                                        }}/>

                                    </Paper>
                                    : null}
                            </Grid>
                        </div>
                        <Grid item xl lg sm xs>
                            <div>
                                <div style={{float: "right"}}>
                                    <Typography style={{padding: 10, float: "right"}}
                                                variant={"subtitle2"}> TL {
                                        (JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                        (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0)
                                    }
                                        {!dropdown[item.id] ?
                                            <ArrowDropDown fontSize={"large"} style={{marginBottom:-12, cursor:"pointer"}} onClick={() => {
                                                let t = !dropdown[item.id]
                                                setDropdown({...dropdown, [item.id]: t})
                                            }}
                                            /> : <ArrowDropUp fontSize={"large"} style={{marginBottom:-12, cursor:"pointer"}} onClick={() => {
                                                let t = !dropdown[item.id]
                                                setDropdown({...dropdown, [item.id]: t})
                                            }}
                                            />}

                                    </Typography>
                                    <br/>
                                    {!JSON.parse(item.reconciliation_list).length ?
                                        <Button size={"small"} variant={"contained"} color={"primary"}
                                                style={{borderRadius: 30}}
                                                onClick={() => openDialog(item.name, item.id)}>
                                            Get started
                                        </Button> : <Button
                                            onClick={() => {
                                                setReconcileInfo({title: item.name, id: item.id})
                                                handleReconciliationOpenCLose()
                                            }}
                                            size={"small"} variant={"contained"} color={"primary"}
                                            style={{borderRadius: 30}}
                                        > Reconcile</Button>}
                                </div>
                            </div>
                        </Grid>

                    </Grid>
                        <Grid container style={{marginLeft: 30, marginBottom: 20}}>
                            { !dropdown[item.id] ?null:JSON.parse(item.reconciliation_list).map((item_s, index) => {
                                let [total_amount, current_amount] = getIcon((JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                    (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0),
                                    item_s.amount, item_s.date, index, item
                                )

                                return <div>
                                    <Typography style={{textAlign: "center", marginLeft: -95, color: "grey"}}
                                                variant={"subtitle2"}>{item_s.date} </Typography>

                                    {
                                        total_amount === current_amount ? <div style={{display: "flex"}}>
                                                <Tooltip title="Successfully reconciled!" aria-label="add">

                                                    <CheckCircle fontSize={"large"}
                                                                 style={show_hover.item_s === item_s.id ? {
                                                                     color: "green",
                                                                     cursor: "pointer",
                                                                     border: "2px solid green",
                                                                     borderRadius: "50%"
                                                                 } : {color: "green", cursor: "pointer"}}


                                                                 onMouseEnter={() => {

                                                                     setShowHover({
                                                                         total_amount,
                                                                         current_amount,
                                                                         item_s: item_s.id,
                                                                         name: item.name,
                                                                         id: item.id,
                                                                         amount: item_s.amount,
                                                                         an_other_amount: (JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                                                             (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0),
                                                                         date: item_s.date
                                                                     })
                                                                 }}
                                                                 onClick={() => {
                                                                     setReconcileInfo({
                                                                         title: item.name,
                                                                         id: item.id,
                                                                         date_p: index > 0 ? JSON.parse(item.reconciliation_list)[index - 1].date : null,
                                                                         date: item_s.date
                                                                     })
                                                                     handleReconciliationOpenCLose()
                                                                 }}
                                                        // onClick={() => {
                                                        //     setDate(item_s.date_created)
                                                        //
                                                        //     openDialog(item.name, item.id, item_s.id, item_s.amount,
                                                        //         (JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                                        //         (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0), item_s.date)
                                                        // }}
                                                    />
                                                </Tooltip>
                                                <Divider style={{width: 100, marginTop: 16, height: 4}}/>
                                            </div>
                                            : <div style={{display: "flex"}}>
                                                <Tooltip
                                                    title="Balance do not match!"
                                                    aria-label="add">

                                                    <Cancel

                                                        onMouseEnter={() => {
                                                            setShowHover({
                                                                total_amount,
                                                                current_amount,
                                                                item_s: item_s.id,
                                                                name: item.name,
                                                                id: item.id,
                                                                amount: item_s.amount,
                                                                an_other_amount: (JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                                                    (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0),
                                                                date: item_s.date
                                                            })
                                                        }}
                                                        fontSize={"large"} style={show_hover.item_s === item_s.id ? {
                                                        color: "red",
                                                        cursor: "pointer",
                                                        border: "2px solid red",
                                                        borderRadius: "50%"
                                                    } : {color: "red", cursor: "pointer"}}
                                                        onClick={() => {
                                                            setReconcileInfo({
                                                                title: item.name,
                                                                id: item.id,
                                                                date_p: index > 0 ? JSON.parse(item.reconciliation_list)[index - 1].date : null,
                                                                date: item_s.date
                                                            })
                                                            handleReconciliationOpenCLose()
                                                        }}
                                                        // onClick={() => {
                                                        //     setDate(item_s.date_created)
                                                        //     openDialog(item.name, item.id, item_s.id, item_s.amount,
                                                        //         (JSON.parse(item.credit_debit).filter((item) => item.type == 2)).reduce((prev, cur) => prev + cur.amount, 0) -
                                                        //         (JSON.parse(item.credit_debit).filter((item) => item.type == 1)).reduce((prev, cur) => prev + cur.amount, 0), item_s.date)
                                                        // }}
                                                    />
                                                </Tooltip>
                                                <Divider style={{width: 100, marginTop: 16, height: 4}}/>
                                            </div>
                                    }
                                </div>
                            })}

                        </Grid>
                        {JSON.parse(item.reconciliation_list).length ? <Button size={"small"} color={"primary"}
                                                                               onClick={() => openDialog(item.name, item.id)}>
                            Add Period
                        </Button> : null}
                        <Divider/>
                    </>
                })}

            </Paper>
            {
                dialog ?
                    <Dialog onClose={openDialog} aria-labelledby="simple-dialog-title" open={dialog} maxWidth={"md"}
                            fullWidth>
                        <DialogTitle id="simple-dialog-title">{selectedAccount.reconciliation_id ? "Edit " : ""} Ending
                            statement balance</DialogTitle>
                        <Divider/>

                        <Typography style={{marginLeft: 10, padding: 10, fontWeight: "bold"}}
                                    variant={"subtitle1"}> {selectedAccount.name}</Typography>
                        <Typography style={{marginLeft: 10, padding: 10}}
                                    variant={"subtitle2"}>Enter the ending balance as it appears on your statement
                        </Typography>
                        <TextField label={"Ending Balance Date"}
                                   InputProps={{inputProps: {max: DateToday()}}}
                                   variant={"outlined"} value={date}
                                   onChange={(e) => setDate(e.target.value)} type={"date"} fullWidth
                                   style={{width: "95%", margin: "auto", marginBottom: 30}}/>
                        <TextField label={"Enter Ending Amount"} variant={"outlined"} fullWidth value={amount}
                                   onChange={(e) => setAmount(e.target.value)}
                                   style={{width: "95%", margin: "auto", marginBottom: 30}}/>
                        <div style={{width: 500, margin: "auto", marginBottom: 30, display: "flex"}}>
                            <Button style={{margin: 10}} variant={"contained"} color={"primary"} fullWidth
                                    onClick={SubmitReconciliation}>Submit</Button>
                            {selectedAccount.reconciliation_id ?
                                <Button component={A} href={"/crm/acctransactions/"} style={{margin: 10}} fullWidth
                                        variant={"contained"} color={"primary"}>Edit Transactions</Button> : null}
                        </div>

                    </Dialog>
                    : null
            }
            <ReconcileTransactions title={reconcile_info.title} id={reconcile_info.id} prev_date={reconcile_info.date_p}
                                   current_date={reconcile_info.date} open={open_reconciliation}
                                   handleClose={handleReconciliationOpenCLose}/>
        </Grid>
    </Grid>

}

export default Recompilation