import React, {Fragment, useEffect, useState} from "react";
import Paper from "@material-ui/core/Paper";
import baseURL from "../helpingFunctions/baseUrl";
import {Button, Divider, Fab, MenuItem, TextField} from "@material-ui/core";
import ListSubheader from "@material-ui/core/ListSubheader";
import {DeleteForever, Done, FileCopy} from "@material-ui/icons";
import {makeStyles} from "@material-ui/core/styles";
import axios from 'axios'
import DateToday from "../helpingFunctions/date_today";
import Typography from "@material-ui/core/Typography";

const useStyles = makeStyles(theme => ({
    Divider: {
        marginTop: 20,
        marginBottom: 20
    },
    Container: {
        height: 551,

        overflowY: "scroll"
    },
    TextField: {
        marginTop: 15,
        width: 414
    },
    TextFieldDuelFirst: {
        width: 220
    },
    TextFieldDuelSecond: {
        width: 195
    },
    SubMenu: {
        marginLeft: 20,
    },
    SubButtons: {
        marginLeft: 6,
        boxShadow: "none"
    },
    SubSuccess: {
        marginLeft: 6,
        color: "green !important",
        border: "1px solid green",
        boxShadow: "none"
    },
}));

const transactions = [
    {
        value: '1',
        label: 'Deposit',
    },
    {
        value: '2',
        label: 'Withdrawal',
    },
];

function AddJournal(props) {
    useEffect(() => {
        getSplitAccounts()
    }, [1])

    const {
        Account,
        DOW,
        Description,
        Date,
        Notes,
        totalAmount,
        split,
        id,
        setSave,
        save,
        setAccount,
        setDOW,
        setDescription,
        setDate,
        setId,
        setNotes,
        setTotalAmount,
        setSplit,
        reviewed,
        setReviewed
    } = props


    const classes = useStyles();


    const [splitAccounts, setSplitAccounts] = useState([]);


    console.log(props.Description)


    function getSplitAccounts() {
        let result;
        axios.get(baseURL + "crm/api/split-accounts/", {
            params: {
                user: localStorage.getItem("user")
            }
        }).then((r) => {
            result = r.data
            setSplitAccounts(result)
        })
    }

    console.log(split.filter((item) => item.type == 1).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next))

    function Display(dup) {
        if (split.filter((item) => item.type == 1).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)
            !== split.filter((item) => item.type == 2).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)) {

        } else {


            const test = {
                "user": localStorage.getItem("user"),
                "credit_debit": split,
                "description": Description,
                "date": Date,
                "type": DOW,
                "notes": Notes,
                "reviewed": reviewed,
            }

            if (!id || dup === "D")
                axios.post(baseURL + "crm/api/transections-list-create/", test).then((r) => {
                        console.log(r.data)
                        props.setSave(!props.save)
                    }
                )
            else if (id && dup === "del") {
                axios.delete(baseURL + "crm/api/transections-rud/" + id).then(() => {
                    props.setSave(!props.save)
                })
            } else {
                axios.put(baseURL + "crm/api/transections-rud/" + id, test).then((r) => {
                        console.log(r.data)
                        props.setSave(!props.save)
                    }
                )
            }

            console.log(test);
        }

    }

    return (
        <div style={{minWidth: 460}}>
            <Paper style={{padding: 10, borderBottom: "1px solid #e0e0e0", borderRadius: 0, height: "fit-content"}}
                   elevation={0}>
                <div>
                    Edit Journal details
                </div>
                <Divider className={classes.Divider}/>

                <div className={classes.Container}>
                    <TextField className={classes.TextField}
                               id="outlined-password-input"
                               label="Description"
                               type="text"
                               value={Description}
                               autoComplete="current-password"
                               variant="outlined"
                               onChange={(e) => {
                                   setDescription(e.target.value)
                               }}
                    />

                    <div style={{marginTop: 15}}>
                        <TextField
                            className={classes.TextFieldDuelFirst}
                            id="outlined-password-input"
                            label="Date"
                            type="date"
                            value={Date}
                            variant="outlined"
                            onChange={(e) => {
                                setDate(e.target.value)
                            }}
                        />
                        <div style={{float: "right", marginRight: 20}}>
                            <Typography>Total</Typography>
                            <Typography
                                variant={"h6"}>{split.filter((item) => item.type == 1).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next) === split.filter((item) => item.type == 2).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next) ? split.filter((item) => item.type == 1).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next) :
                                <span style={{color: "red"}}>Unbalanced</span>}</Typography>
                        </div>

                    </div>
                    <Divider className={classes.Divider}/>
                    <Typography style={{paddingLeft: 40, paddingRight: 40}} variant={"h5"}> Credit <span
                        style={{float: "right"}}>Debit</span></Typography>

                    <Divider className={classes.Divider}/>
                    <div style={{maxWidth: 415}}>
                        {
                            split.map((k, i) => {
                                let id = k.id;
                                let index = i;
                                if (split.find((item) => item.id === id).description) {
                                    split.find((item) => item.id === id).cus = true
                                }
                                return <Fragment>
                                    <TextField
                                        className={classes.TextField}
                                        id="standard-select-currency"
                                        label="Category"
                                        select
                                        variant="outlined"
                                        value={split.find((item) => item.id === id).category}
                                        onChange={(e) => {
                                            let temp = split;
                                            temp.find((item) => item.id === id).category = e.target.value;
                                            setSplit([...temp])
                                        }}
                                    >
                                        {splitAccounts.map((item) => {
                                            return [
                                                <ListSubheader>{item.name}</ListSubheader>,
                                                item.accounting_child.map((it) => {
                                                    return <MenuItem className={classes.SubMenu}
                                                                     value={it.id}>{it.name}</MenuItem>
                                                })
                                            ]
                                        })}
                                    </TextField>

                                    {
                                        split.find((item) => item.id === id).cus ?

                                            <TextField className={classes.TextField}
                                                       id="standard-select-currency"
                                                       label="Description"
                                                       variant="outlined"
                                                       value={split.find((item) => item.id === id).description}
                                                       onChange={(e) => {
                                                           let temp = split;
                                                           temp.find((item) => item.id === id).description = e.target.value;
                                                           setSplit([...temp])
                                                       }}
                                            />
                                            : null
                                    }
                                    <div style={{marginTop: 10}}>
                                        <TextField className={classes.TextFieldDuelSecond}
                                                   label="Amount"
                                                   variant="outlined"
                                                   id={index}
                                                   style={k.type == 1 ? {float: "right"} : {float: "left"}}
                                                   value={split.find((item) => item.id === id).amount}
                                                   onChange={(e) => {
                                                       let temp = split;
                                                       temp.find((item) => item.id === id).amount = e.target.value;
                                                       setSplit([...temp])
                                                   }}
                                        />

                                        {index <= 1 ? null : <Button onClick={() => {
                                            let temp = split;
                                            split.splice(index, 1)
                                            setSplit([...temp])
                                        }} size="small" style={{boxShadow: "none"}}>
                                            <DeleteForever/>
                                        </Button>}
                                    </div>
                                    <Button style={{color: "Blue"}}
                                            onClick={() => {
                                                let temp = split;
                                                temp.find((item) => item.id === id).cus =
                                                    !temp.find((item) => item.id === id).cus;
                                                temp.find((item) => item.id === id).customer = "";

                                                setSplit([...temp])
                                            }}

                                    >
                                        {!split.find((item) => item.id === id).cus ? "Add Description" : "Remove Description"} </Button>

                                </Fragment>
                                // return <Split id={k.id} index={i}/>
                            })
                        }
                    </div>

                    <Divider style={{marginTop: 40}}/>

                    <div style={{textAlign: "center", marginTop: 10}}>
                        <div style={{paddingLeft: 40, paddingRight: 40}}>
                            <div style={{float: "left"}}>
                                <Button variant="outlined" size="small" color="primary"
                                        style={{backgroundColor: "white"}} onClick={() => {
                                    setSplit([...split, {
                                        id: split[split.length - 1].id + 1,
                                        category: "",
                                        customer: "",
                                        amount: 0,
                                        type: 2,
                                        cus: false
                                    }])
                                }}>
                                    Add Credit
                                </Button>
                                <Typography><span>Total Credit is </span><span
                                    style={{fontWeight: 20}}>{split.filter((item) => item.type == 1).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)}</span></Typography>
                            </div>
                            <div style={{float: "right"}}>
                                <Button variant="outlined" size="small" color="primary"
                                        style={{backgroundColor: "white", marginLeft: 20}} onClick={() => {
                                    setSplit([...split, {
                                        id: split[split.length - 1].id + 1,
                                        category: "",
                                        customer: "",
                                        amount: 0,
                                        type: 1,
                                        cus: false
                                    }])
                                }}>
                                    Add Debit
                                </Button>
                                <Typography><span>Total Debit is </span><span
                                    style={{fontWeight: 20}}>{split.filter((item) => item.type == 2).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)}</span></Typography>
                            </div>
                        </div>

                    </div>
                    <TextField className={classes.TextField}
                               id="outlined-password-input"
                               label="Notes"
                               type="text"
                               multiline
                               value={Notes}
                               autoComplete="current-password"
                               variant="outlined"
                               onChange={(e) => {
                                   setNotes(e.target.value)
                               }}
                    />
                    <div style={{marginTop: 10}}>Transaction last modified on <DateToday/>
                    </div>
                </div>
                <Divider style={{marginTop: 13, marginBottom: 5}}/>

                <div style={{textAlign: "center"}}>
                    {/*{*/}
                    {/*    split.map(item => parseInt(item.amount)).reduce((prev, next) => prev + next)*/}
                    {/*    !== parseInt(totalAmount) && split.length > 1 ?*/}
                    {/*        <div style={{color: "red"}}>Split sum is not equal to total amount </div> : null*/}
                    {/*}*/}
                    <Fab size="small" style={{boxShadow: "none"}} onClick={() => {
                        Display("del")
                    }}>
                        <DeleteForever/>
                    </Fab>
                    <Fab size="small" className={classes.SubButtons} onClick={() => {
                        Display("D")
                    }}>
                        <FileCopy/>
                    </Fab>
                    <Fab disabled={!split[split.length - 1].category} variant="extended" size="small"
                         className={reviewed ? classes.SubSuccess : classes.SubButtons}
                         onClick={() => setReviewed(!reviewed)}>

                        <Done/> Mark as reviewed
                    </Fab>
                    <Fab variant="extended" color={"primary"} size="small"
                         className={classes.SubButtons} onClick={() => {
                        Display();
                    }}>

                        Save
                    </Fab>
                </div>
            </Paper>
        </div>
    )

}

export default AddJournal;