import React from "react";
import {useRoutes} from "hookrouter";
import Transactions from "../transections";
import Recompilation from "../reconciliation";



const routes = {
    "/crm/acctransactions/" : () => <Transactions/>,
    "/crm/reconciliation/" : () => <Recompilation/>,
};

function Route() {
  const routeResult = useRoutes(routes);
  return(
        <>
          {routeResult}
        </>
  )
}

export default Route;


