import React, {useEffect, useState} from "react";
import MaterialTable, {MTableToolbar} from "material-table";
import {Fab} from "@material-ui/core";
import {Add, CheckCircle, Close} from "@material-ui/icons";
import AddTransaction from "./add_transaction";
import tableIcons from "./icons";
import axios from "axios";
import baseURL from "../helpingFunctions/baseUrl";
import AddJournal from "../transections/addJournal"


function TableTransactions(props) {
    const [data, setData] = useState();

    const {
        DOW,
        add_transaction,
        id,
        Account,
        reviewed,
        Description,
        Notes,
        totalAmount,
        split,
        vendor,


        setId,
        setAccount,
        setReviewed,
        setDescription,
        setDate,
        setNotes,
        setTotalAmount,
        setVendor,
        setSplit,


        setDOW,
        setAdd_transaction,

        Clear

    } = props


    const [save, setSave] = useState(false);

    const columns = [
        {title: 'Description', field: 'description'},
        {title: 'Date', field: 'date'},
        // {
        //     title: 'Account', field: 'name', render: (rowData) => {
        //         if (rowData.type == 1) {
        //             return rowData.credit_debit.filter(e => e.type === "1")[0].name;
        //         } else if (rowData.type == 2) {
        //             return rowData.credit_debit.filter(e => e.type === "2")[0].name;
        //         }
        //     }
        // },
        {
            title: 'Amount', field: 'amount', render: (rowData) => {
                if (rowData.type == 1) {
                    return rowData.credit_debit.filter(e => e.type === "1")[0].amount;
                } else if (rowData.type == 2) {
                    return rowData.credit_debit.filter(e => e.type === "2")[0].amount;
                } else if (rowData.type == 3) {
                    return rowData.credit_debit.filter((item) => item.type == 1).map(item => parseInt(item.amount)).reduce((prev, next) => prev + next);
                }
            }
            
        },
        {
            title: 'Type', field: 'type', lookup: {
                '1': 'Deposit',
                '2': 'Withdrawal',
                '3': 'Journal',
            }
        },
        {
            title: 'Reviewed',
            field: 'reviewed',
            lookup: {
                true: 'Reviewed',
                false: 'Unreviewed',
            },
            render: (rowData) => rowData.reviewed == true ? <CheckCircle style={{color: "#71c456", fontSize: 25}}/> :
                <CheckCircle style={{color: "#d4d4d4", fontSize: 25}}/>
        },
    ]

    function getData() {
        axios.get(baseURL + "crm/api/transections-list-create/", {
            params: {user: localStorage.getItem("user")}
        }).then((r) => {
                if (r.data) {
                    if(props.filter && props.current_date && props.prev_date){
                        setData(r.data.filter((item) => {
                            return  ((new Date(item.date) > new Date(props.prev_date))  && (new Date(item.date) <= new Date(props.current_date))) && (item.credit_debit.filter((it) => it.category == props.filter).length > 0)
                        }))
                    }
                    else if(props.filter) {
                        setData(r.data.filter((item) => {
                            return item.credit_debit.filter((it) => it.category == props.filter).length > 0
                        }))
                    }
                    else {
                        setData(r.data)
                    }
                }

            }
        )

    }
    console.log(data)
    useEffect(() => {
        getData();
    }, [1, save]);

    function rowClick(e, rowData) {
        let res;
        let new_res = JSON.parse(JSON.stringify(rowData))
        if (new_res.type == 1) {
            res = new_res.credit_debit.splice(new_res.credit_debit.findIndex(e => e.type === "1"), 1);
            res = res[0]
            console.log(new_res)
            setAccount(res.category)
            setTotalAmount(res.amount)
            setVendor(res.vendor)
        } else if (new_res.type == 2) {
            res = new_res.credit_debit.splice(new_res.credit_debit.findIndex(e => e.type === "2"), 1);
            res = res[0]
            console.log(new_res)
            setAccount(res.category)
            setTotalAmount(res.amount)
            setVendor(res.vendor)
        }


        setDescription(new_res.description)
        setDate(new_res.date)
        setDOW(new_res.type)
        setNotes(new_res.notes)
        setReviewed(new_res.reviewed)
        setSplit(new_res.credit_debit)
        setId(new_res.id)
        setAdd_transaction(true);

    }

    return (
        <div style={{display: "flex"}}>
            <div style={{width: "100%", minWidth: 500}}>
                <MaterialTable
                    style={{boxShadow: "none"}}
                    icons={tableIcons}
                    title=""
                    columns={columns}
                    data={data}
                    onRowClick={rowClick}
                    options={{
                        filtering: true,
                        paginationType: "stepped",
                        pageSizeOptions: [],
                        pageSize: 10,
                        maxBodyHeight: 600
                    }}
                    components={{
                        Toolbar: props => (
                            <div>
                                <div style={{marginRight: 10, float: "right"}}>
                                    <Fab style={{boxShadow: "none", marginTop: 6}} size={"small"}
                                         color="primary"
                                         aria-label="add" onClick={() => {
                                        Clear()
                                        setAdd_transaction(!add_transaction)
                                    }}>
                                        {add_transaction ? <Close/> : <Add/>}
                                    </Fab>
                                </div>
                                <MTableToolbar {...props} />
                            </div>
                        ),
                    }}
                />
            </div>
            {add_transaction ? DOW == 3 ? <AddJournal
                Account={Account}
                DOW={DOW}
                Description={Description}
                Date={props.Date}
                Notes={Notes}
                totalAmount={totalAmount}
                split={split}
                save={save}
                id={id}
                reviewed={reviewed}
                setReviewed={setReviewed}
                setAccount={setAccount}
                setDOW={setDOW}
                setDescription={setDescription}
                setDate={setDate}
                setNotes={setNotes}
                setTotalAmount={setTotalAmount}
                setSplit={setSplit}
                setSave={setSave}
                setId={setId}
            /> : <AddTransaction
                Account={Account}
                DOW={DOW}
                Description={Description}
                Date={props.Date}
                Notes={Notes}
                totalAmount={totalAmount}
                vendor={vendor}
                split={split}
                save={save}
                id={id}
                reviewed={reviewed}
                setReviewed={setReviewed}
                setAccount={setAccount}
                setDOW={setDOW}
                setDescription={setDescription}
                setDate={setDate}
                setNotes={setNotes}
                setTotalAmount={setTotalAmount}
                setVendor={setVendor}
                setSplit={setSplit}
                setSave={setSave}
                setId={setId}

                filter={props.filter}
                current_date={props.current_date}
                prev_date={props.prev_date}
            /> : null}
        </div>
    )
}

export default TableTransactions;